// MARK: - AppDeepLink and Associated Types

enum AppDeepLink: Equatable {
    case profile(id: String)
    case paymentConfirmation
    case adminSettings
    case unknown

    init(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let host = components.host, host == "myapp.com" else {
            self = .unknown
            return
        }

        let pathComponents = components.path.split(separator: "/").map { String($0) }

        if pathComponents.count == 2 && pathComponents[0] == "profile" {
            self = .profile(id: pathComponents[1])
        } else if pathComponents.count == 1 && pathComponents[0] == "payment" && components.path == "/payment/confirm" {
            self = .paymentConfirmation
        } else if pathComponents.count == 1 && pathComponents[0] == "admin" && components.path == "/admin/settings" {
            self = .adminSettings
        } else {
            self = .unknown
        }
    }
}

