// MARK: - DeepLinkCoordinator

class DeepLinkCoordinator: ObservableObject {
    @Published var deepLink: AppDeepLink? {
        didSet {
            // Optional: You could log or perform other actions when a deep link is set
            print("DeepLinkCoordinator: Deep link set to \(String(describing: deepLink))")
        }
    }

    func handleURL(_ url: URL) {
        print("DeepLinkCoordinator: Handling URL: \(url.absoluteString)")
        self.deepLink = AppDeepLink(url: url)
    }
}

// MARK: - Root View and App Structure

struct ContentView: View {
    @EnvironmentObject var deepLinkCoordinator: DeepLinkCoordinator
    @State private var selection: String? = nil // Used for programmatic navigation

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                Text("Welcome to My App!")
                    .font(.largeTitle)
                    .padding()

                NavigationLink(destination: Text("Home Dashboard"), tag: "home", selection: $selection) {
                    EmptyView()
                }

                // Example of how to trigger navigation with deep link, for testing
                Button("Test Profile 123") {
                    deepLinkCoordinator.deepLink = .profile(id: "123")
                }
                Button("Test Payment Confirm") {
                    deepLinkCoordinator.deepLink = .paymentConfirmation
                }
                Button("Test Admin Settings") {
                    deepLinkCoordinator.deepLink = .adminSettings
                }
                Button("Test Unknown Link") {
                    deepLinkCoordinator.deepLink = .unknown
                }
            }
            .navigationTitle("My App Home")
            .navigationBarTitleDisplayMode(.inline)
        }
        .onAppear {
            // Ensure initial deep link is processed if set during app launch
            if deepLinkCoordinator.deepLink != nil {
                navigate(to: deepLinkCoordinator.deepLink)
            }
        }
        .onChange(of: deepLinkCoordinator.deepLink) { newDeepLink in
            navigate(to: newDeepLink)
        }
    }

    @ViewBuilder
    private func navigate(to deepLink: AppDeepLink?) -> some View {
        switch deepLink {
        case .profile(let id):
            NavigationLink(
                destination: ProfileView(viewModel: ProfileViewModel(profileID: id)),
                tag: "profile-\(id)",
                selection: $selection,
                label: { EmptyView() }
            )
            .onAppear { selection = "profile-\(id)" }
        case .paymentConfirmation:
            NavigationLink(
                destination: PaymentConfirmationView(viewModel: PaymentConfirmationViewModel()),
                tag: "paymentConfirmation",
                selection: $selection,
                label: { EmptyView() }
            )
            .onAppear { selection = "paymentConfirmation" }
        case .adminSettings:
            NavigationLink(
                destination: AdminSettingsView(viewModel: AdminSettingsViewModel()),
                tag: "adminSettings",
                selection: $selection,
                label: { EmptyView() }
            )
            .onAppear { selection = "adminSettings" }
        case .unknown:
            NavigationLink(
                destination: UnknownDeepLinkView(),
                tag: "unknown",
                selection: $selection,
                label: { EmptyView() }
            )
            .onAppear { selection = "unknown" }
        case .none:
            // No deep link or it has been consumed/cleared
            // You might want to navigate back to home or just do nothing
            // For now, let's reset selection to nil to prevent staying on a deep link view if the link is cleared
            if selection != nil && !selection!.hasPrefix("home") { // Avoid clearing home if that's where we are
                selection = nil
            }
        }
    }
}


@main
struct MyApp: App {
    @StateObject private var deepLinkCoordinator = DeepLinkCoordinator()

    var body: some View {
        WindowGroup {
            ContentView()
                .environmentObject(deepLinkCoordinator)
                .onOpenURL { url in
                    print("App received URL: \(url.absoluteString)")
                    deepLinkCoordinator.handleURL(url)
                }
        }
    }
}

